"""Configuration loader — merges all config sources.

Load order (later sources override earlier ones):
  1. Base Python config class (config/base.py)
  2. Environment-specific Python config (config/development.py or config/production.py)
  3. YAML settings file (settings.yaml)
  4. .env file (environment variable overrides)

DO NOT MODIFY THIS FILE — it is the source of truth for how
configuration is assembled. Fix the config files instead.
"""
import os
import yaml
from pathlib import Path
from dotenv import dotenv_values


def _find_project_root():
    """Walk up from this file to find the project root (where .env lives)."""
    current = Path(__file__).resolve().parent.parent
    return current


def _load_yaml_settings(root: Path) -> dict:
    """Load and return settings.yaml as a dict."""
    yaml_path = root / "settings.yaml"
    if not yaml_path.exists():
        return {}
    with open(yaml_path) as f:
        return yaml.safe_load(f) or {}


def _load_env_file(root: Path) -> dict:
    """Load .env file and return as dict."""
    env_path = root / ".env"
    if not env_path.exists():
        return {}
    return dotenv_values(env_path)


def _get_config_class(env_name: str):
    """Return the config class for the given environment."""
    if env_name == "production":
        from .production import ProductionConfig
        return ProductionConfig
    else:
        from .development import DevelopmentConfig
        return DevelopmentConfig


def _extract_class_config(config_class) -> dict:
    """Extract all uppercase attributes from a config class."""
    return {
        key: getattr(config_class, key)
        for key in dir(config_class)
        if key.isupper() and not key.startswith("_")
    }


def load_config() -> dict:
    """Load and merge all configuration sources.

    Returns a flat dict with all configuration values.
    The merge order ensures that more specific sources
    override more general ones.
    """
    root = _find_project_root()

    # 1. Load environment name from .env first (needed to pick config class)
    env_vars = _load_env_file(root)
    env_name = env_vars.get("APP_ENV", os.environ.get("APP_ENV", "development"))

    # 2. Load Python config class
    config_class = _get_config_class(env_name)
    config = _extract_class_config(config_class)

    # 3. Merge YAML settings (flattened with dot notation converted to uppercase)
    yaml_settings = _load_yaml_settings(root)
    yaml_flat = _flatten_yaml(yaml_settings)
    config.update(yaml_flat)

    # 4. Override with .env values (highest precedence)
    for key, value in env_vars.items():
        if key.isupper():
            config[key] = value

    return config


def _flatten_yaml(data: dict, prefix: str = "") -> dict:
    """Flatten nested YAML dict into uppercase keys.

    Example:
        {"redis": {"host": "localhost", "port": 6379}}
        becomes
        {"REDIS_HOST": "localhost", "REDIS_PORT": 6379}
    """
    result = {}
    for key, value in data.items():
        full_key = f"{prefix}_{key}".upper() if prefix else key.upper()
        if isinstance(value, dict):
            result.update(_flatten_yaml(value, full_key))
        else:
            result[full_key] = value
    return result


def load_docker_compose(root: Path = None) -> dict:
    """Load docker-compose.yml and return as dict.

    Used by tests to verify config consistency with service definitions.
    """
    if root is None:
        root = _find_project_root()
    dc_path = root / "docker-compose.yml"
    if not dc_path.exists():
        return {}
    with open(dc_path) as f:
        return yaml.safe_load(f) or {}


def get_docker_service_port(dc: dict, service: str) -> int:
    """Extract the container-internal port for a service from docker-compose.

    Given a port mapping like '6380:6379', returns the internal port (6379).
    """
    services = dc.get("services", {})
    svc = services.get(service, {})
    ports = svc.get("ports", [])
    if not ports:
        return 0
    # Take the first port mapping
    mapping = str(ports[0])
    if ":" in mapping:
        return int(mapping.split(":")[1])
    return int(mapping)


def get_docker_env_var(dc: dict, service: str, var_name: str) -> str:
    """Extract an environment variable value from a docker-compose service."""
    services = dc.get("services", {})
    svc = services.get(service, {})
    env_list = svc.get("environment", [])

    if isinstance(env_list, dict):
        return str(env_list.get(var_name, ""))

    # List format: ["KEY=value", ...]
    for entry in env_list:
        entry_str = str(entry)
        if "=" in entry_str:
            k, v = entry_str.split("=", 1)
            if k.strip() == var_name:
                return v.strip()
    return ""
